local a={}function a.vec4FixNegativeSize(b)return vec(math.min(b.x,b.z),math.min(b.y,b.w),math.max(b.x,b.z),math.max(b.y,b.w))end;function a.vec4SetPos(b,c,d)local e=b.xy;b.x,b.y=c,d;b.z,b.w=c-e.x,d-e.y;return b end;function a.vec4SetOtherPos(b,f,g)local e=b.zw;b.z,b.w=f,g;b.x,b.y=f-e.x,g-e.y;return b end;function a.vec4Size(b)return b.zw-b.xy end;function a.vec2(h,d)local i,j=type(h),type(d)if i=="Vector2"then return h:copy()elseif i=="number"and j=="number"then return vec(h,d)else error("Invalid Vector2 parameter, expected Vector2 or (number, number), instead got ("..i..", "..j..")")end end;function a.vec3(h,d,f)local i,j,k=type(h),type(d),type(f)if i=="Vector3"then return h:copy()elseif i=="number"and j=="number"and k=="number"then return vec(h,d,f)else error("Invalid Vector3 parameter, expected Vector3 or (number, number, number), instead got ("..i..", "..j..", "..k..")")end end;function a.vec4(h,d,f,g)local i,j,k,l=type(h),type(d),type(f),type(g)if i=="Vector4"then return h:copy()elseif i=="number"and j=="number"and k=="number"and l=="number"then return vectors.vec4(h,d,f,g)else error("Invalid Vector4 parameter, expected Vector4 or (number, number, number, number), instead got ("..i..", "..j..", "..k..", "..l..")")end end;function a.deepCopy(m)local n={}local o=getmetatable(m)if o then setmetatable(n,o)end;for p,q in pairs(m)do if type(q)=="table"then q=a.deepCopy(q)end;if type(q):find("Vector")then q=q:copy()end;n[p]=q end;return n end;return a